#nullable enable // autogenerated  

using System.Collections.Generic;
using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Difficulties;
using MVZ2.Vanilla.Callbacks;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;
using UnityEngine;

namespace MVZ2.GameContent.Buffs.Enemies
{
    [AutoBuffDefinition(VanillaBuffNames.Enemy.WraithBuff)]
    public class WraithBuff : BuffDefinition
    {
        public WraithBuff(string nsp, string name) : base(nsp, name)
        {
            AddModifier(ColorModifier.Multiply(EngineEntityProps.TINT, PROP_TINT_MULTIPLIER));
            AddModifier(new BooleanModifier(VanillaEntityProps.ETHEREAL, PROP_ETHEREAL));
            var hpbarModifier = new IntModifier(LogicEntityProps.HP_BAR_VISIBILITY, IntegerOperator.Set, PROP_HP_BAR_VISIBLITY)
            {
                Condition = m => m == HPBarVisibility.HIDDEN
            };
            AddModifier(hpbarModifier);
            AddModifier(new FloatModifier(LogicEntityProps.SHADOW_ALPHA, NumberOperator.Multiply, PROP_SHADOW_ALPHA));
            AddTrigger(VanillaLevelCallbacks.PRE_ENTITY_TAKE_DAMAGE, PreEntityTakeDamageCallback, priority: VanillaCallbackPriorities.MULTIPLY);
        }
        public override void OnCreate(Buff buff)
        {
            base.OnCreate(buff);
            buff.SetProperty(PROP_ETHEREAL, true);
            buff.SetProperty(PROP_SHADOW_ALPHA, SHADOW_ALPHA_MIN);
        }
        public override void PostAdd(Buff buff)
        {
            base.PostAdd(buff);
            // 若添加 buff 时未显式设置所需等级，则从实体属性读取  
            if (buff.GetProperty<int[]>(PROP_REQUIRED_LIGHT_LEVELS) == null)
            {
                var entity = buff.GetEntity();
                var levels = entity?.GetProperty<int[]>(LogicEntityProps.WRAITH_REQUIRED_LIGHT_LEVELS);
                buff.SetProperty(PROP_REQUIRED_LIGHT_LEVELS, levels);
            }
            buff.SetProperty(PROP_HP_BAR_VISIBLITY, HPBarVisibility.NORMAL);
            buff.SetProperty(PROP_TINT_MULTIPLIER, new Color(1, 1, 1, TINT_ALPHA_MIN));
            UpdateIllumination(buff);
        }
        public override void PostUpdate(Buff buff)
        {
            base.PostUpdate(buff);
            UpdateIllumination(buff);
        }
        private void PreEntityTakeDamageCallback(VanillaLevelCallbacks.PreTakeDamageParams param, CallbackResult callbackResult)
        {
            var damageInfo = param.input;
            var entity = damageInfo.Entity;
            if (entity == null)
                return;
            if (damageInfo.Effects.HasEffect(VanillaDamageEffects.WHACK))
                return;
            buffBuffer.Clear();
            entity.GetBuffs<WraithBuff>(buffBuffer);
            if (buffBuffer.Count <= 0)
                return;
            // 只有已显形(非 ethereal)的亡魂才能被正常打击  
            foreach (var buff in buffBuffer)
            {
                if (buff.GetProperty<bool>(PROP_ETHEREAL))
                {
                    damageInfo.Multiply(buff.Level.GetGhostTakenDamageMultiplier());
                    break;
                }
            }
        }
        private void UpdateIllumination(Buff buff)
        {
            var entity = buff.GetEntity();
            if (entity == null)
                return;
            bool illuminated = entity.IsAIFrozen() || IsLitByRequiredLevel(buff, entity);
            SetIlluminated(buff, illuminated);
        }
        // 判断实体身上是否有"匹配所需等级"的光源照亮  
        private static bool IsLitByRequiredLevel(Buff buff, Entity entity)
        {
            var levels = buff.GetProperty<int[]>(PROP_REQUIRED_LIGHT_LEVELS);
            if (levels == null || levels.Length <= 0)
                return false;
            // 白天视为等级 0(白光)  
            if (entity.Level.IsDay() && ContainsLevel(levels, 0))
                return true;
            foreach (var sourceId in entity.Level.GetIlluminationLightSources(entity))
            {
                var source = entity.Level.FindEntityByID(sourceId);
                if (!source.ExistsAndAlive())
                    continue;
                if (ContainsLevel(levels, source.GetLightLevel()))
                    return true;
            }
            return false;
        }
        private static bool ContainsLevel(int[] levels, int level)
        {
            if (level < 0)
                return false;
            for (int i = 0; i < levels.Length; i++)
            {
                if (levels[i] == level)
                    return true;
            }
            return false;
        }
        public static void SetIlluminated(Buff buff, bool illuminated)
        {
            if (illuminated)
            {
                SetEverIlluminated(buff, true);
            }
            var entity = buff.GetEntity();
            if (entity == null)
                return;
            float tintSpeed = illuminated ? TINT_SPEED : -TINT_SPEED;
            float shadowSpeed = illuminated ? SHADOW_ALPHA_SPEED : -SHADOW_ALPHA_SPEED;
            bool ethereal = illuminated ? false : true;

            var tint = buff.GetProperty<Color>(PROP_TINT_MULTIPLIER);
            tint.a = Mathf.Clamp(tint.a + tintSpeed, TINT_ALPHA_MIN, TINT_ALPHA_MAX);

            var shadowAlpha = buff.GetProperty<float>(PROP_SHADOW_ALPHA);
            shadowAlpha = Mathf.Clamp(shadowAlpha + shadowSpeed, SHADOW_ALPHA_MIN, SHADOW_ALPHA_MAX);

            buff.SetProperty(PROP_TINT_MULTIPLIER, tint);
            buff.SetProperty(PROP_SHADOW_ALPHA, shadowAlpha);
            buff.SetProperty(PROP_ETHEREAL, ethereal);
        }
        public static void Illuminate(Buff buff)
        {
            buff.SetProperty(PROP_TINT_MULTIPLIER, Color.white);
            buff.SetProperty(PROP_SHADOW_ALPHA, SHADOW_ALPHA_MAX);
            buff.SetProperty(PROP_ETHEREAL, false);
        }
        public static void SetEverIlluminated(Buff buff, bool value)
        {
            buff.SetProperty(PROP_EVER_ILLUMINATED, value);
        }
        public static bool IsEverIlluminated(Buff buff)
        {
            return buff.GetProperty<bool>(PROP_EVER_ILLUMINATED);
        }
        public static bool IsEverIlluminated(Entity entity)
        {
            checkBuffer.Clear();
            entity.GetBuffs<WraithBuff>(checkBuffer);
            foreach (var buff in checkBuffer)
            {
                if (IsEverIlluminated(buff))
                {
                    return true;
                }
            }
            return false;
        }
        // 该亡魂能被哪些光照等级照亮  
        public static readonly VanillaBuffPropertyMeta<int[]> PROP_REQUIRED_LIGHT_LEVELS = new VanillaBuffPropertyMeta<int[]>("required_light_levels");
        public static readonly VanillaBuffPropertyMeta<int> PROP_HP_BAR_VISIBLITY = new VanillaBuffPropertyMeta<int>("hp_bar_visiblity");
        public static readonly VanillaBuffPropertyMeta<bool> PROP_EVER_ILLUMINATED = new VanillaBuffPropertyMeta<bool>("EverIlluminated");
        public static readonly VanillaBuffPropertyMeta<Color> PROP_TINT_MULTIPLIER = new VanillaBuffPropertyMeta<Color>("TintMultiplier");
        public static readonly VanillaBuffPropertyMeta<float> PROP_SHADOW_ALPHA = new VanillaBuffPropertyMeta<float>("ShadowAlpha");
        public static readonly VanillaBuffPropertyMeta<bool> PROP_ETHEREAL = new VanillaBuffPropertyMeta<bool>("Ethereal");
        public const float TINT_ALPHA_MIN = 0.5f;
        public const float TINT_ALPHA_MAX = 1;
        public const float TINT_SPEED = 0.02f;
        public const float SHADOW_ALPHA_MIN = 0;
        public const float SHADOW_ALPHA_MAX = 1;
        public const float SHADOW_ALPHA_SPEED = 0.04f;
        private List<Buff> buffBuffer = new List<Buff>();
        private static List<Buff> checkBuffer = new List<Buff>();
    }
}
